MATERIAL_COUNT = len(MATERIALS)


# ── 查询函数（供 routers/materials.py 使用）─────────────────

def all_categories():
    """返回所有分类及其原料数量"""
    cats = {}
    for m in MATERIALS:
        cat = m.get("category", "未分类")
        cats[cat] = cats.get(cat, 0) + 1
    return cats


def by_category(category):
    """返回指定分类的所有原料"""
    return [m for m in MATERIALS if m.get("category") == category]


def search(query):
    """搜索原料（按名称或分类模糊匹配）"""
    q = query.lower()
    return [m for m in MATERIALS 
            if q in m.get("name", "").lower() 
            or q in m.get("category", "").lower()
            or q in m.get("name_en", "").lower()]


